import{_ as t}from"./chunks/cas-overlay-7.CNvLuIsq.js";import{_ as r}from"./chunks/cas-overlay-6.BPgPhVDD.js";import{_ as a}from"./chunks/cas-overlay-5.Bm3r2Oav.js";import{_ as e,o,c as i,ag as s}from"./chunks/framework.CvgP6Fyv.js";const S=JSON.parse('{"title":"CAS Overlay 开发版文档","description":"","frontmatter":{},"headers":[{"level":1,"title":"CAS Overlay 开发版文档","slug":"cas-overlay-开发版文档","link":"#cas-overlay-开发版文档","children":[{"level":2,"title":"项目简介","slug":"项目简介","link":"#项目简介","children":[]},{"level":2,"title":"版本选择","slug":"版本选择","link":"#版本选择","children":[{"level":3,"title":"CAS Overlay 7.3.x 系列","slug":"cas-overlay-7-3-x-系列","link":"#cas-overlay-7-3-x-系列","children":[]},{"level":3,"title":"CAS Overlay 6.6.x 系列","slug":"cas-overlay-6-6-x-系列","link":"#cas-overlay-6-6-x-系列","children":[]},{"level":3,"title":"CAS Overlay 5.3.x 系列","slug":"cas-overlay-5-3-x-系列","link":"#cas-overlay-5-3-x-系列","children":[]}]},{"level":2,"title":"版本对比","slug":"版本对比","link":"#版本对比","children":[]},{"level":2,"title":"核心功能","slug":"核心功能","link":"#核心功能","children":[]},{"level":2,"title":"技术支持","slug":"技术支持","link":"#技术支持","children":[]},{"level":2,"title":"快速开始","slug":"快速开始","link":"#快速开始","children":[]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]}]}],"relativePath":"dev/cas-overlay/index.md","filePath":"dev/cas-overlay/index.md"}'),n={name:"dev/cas-overlay/index.md"};function d(g,l,c,h,v,p){return o(),i("div",null,[...l[0]||(l[0]=[s('<h1 id="cas-overlay-开发版文档" tabindex="-1">CAS Overlay 开发版文档 <a class="header-anchor" href="#cas-overlay-开发版文档" aria-label="Permalink to &quot;CAS Overlay 开发版文档&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>CAS (Central Authentication Service) 是 Apereo 基金会维护的企业级开源单点登录系统，为企业应用提供统一的身份认证与授权机制。本项目基于不同版本的 CAS Overlay 进行定制化开发，提供完整的开发基座、配置模板和部署方案，旨在帮助开发者快速构建、定制和部署符合企业需求的 CAS 认证服务。</p><h2 id="版本选择" tabindex="-1">版本选择 <a class="header-anchor" href="#版本选择" aria-label="Permalink to &quot;版本选择&quot;">​</a></h2><p>根据您的技术栈和需求，选择适合的 CAS Overlay 版本：</p><h3 id="cas-overlay-7-3-x-系列" tabindex="-1">CAS Overlay 7.3.x 系列 <a class="header-anchor" href="#cas-overlay-7-3-x-系列" aria-label="Permalink to &quot;CAS Overlay 7.3.x 系列&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：21</li><li><strong>构建工具</strong>：Maven 3.9+ / Gradle 9.1.0</li><li><strong>数据库</strong>：MySQL 8.0.33</li><li><strong>缓存</strong>：Redis 7.2.4</li><li><strong>主要特性</strong>：最新版本，支持现代 Java 特性（Java 21），Spring Boot 3.x 架构，OIDC 动态客户端注册，JWT AccessToken 加密签名</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+t+'" alt="CAS Overlay 7.3.x 登录界面"></p><ul><li><strong>文档链接</strong>： <ul><li><a href="./cas-overlay-7.3.x-maven.html">Maven 版本</a></li><li><a href="./cas-overlay-7.3.x-gradle.html">Gradle 版本</a></li></ul></li></ul><h3 id="cas-overlay-6-6-x-系列" tabindex="-1">CAS Overlay 6.6.x 系列 <a class="header-anchor" href="#cas-overlay-6-6-x-系列" aria-label="Permalink to &quot;CAS Overlay 6.6.x 系列&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：11</li><li><strong>构建工具</strong>：Maven 3.9+ / Gradle 7.5</li><li><strong>数据库</strong>：MySQL 8.0.33</li><li><strong>缓存</strong>：Redis 7.2.4</li><li><strong>主要特性</strong>：稳定版本，广泛应用于生产环境，Spring Boot 2.x 架构</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+r+'" alt="CAS Overlay 6.6.x 登录界面"></p><ul><li><strong>文档链接</strong>： <ul><li><a href="./cas-overlay-6.6.x-maven.html">Maven 版本</a></li><li><a href="./cas-overlay-6.6.x-gradle.html">Gradle 版本</a></li></ul></li></ul><h3 id="cas-overlay-5-3-x-系列" tabindex="-1">CAS Overlay 5.3.x 系列 <a class="header-anchor" href="#cas-overlay-5-3-x-系列" aria-label="Permalink to &quot;CAS Overlay 5.3.x 系列&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：1.8</li><li><strong>构建工具</strong>：Maven 3.9+ / Gradle 7.5</li><li><strong>数据库</strong>：MySQL 8.0.33</li><li><strong>缓存</strong>：Redis 7.2.4</li><li><strong>主要特性</strong>：经典版本，适用于旧环境，支持传统 Servlet 规范</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+a+'" alt="CAS Overlay 5.3.x 登录界面"></p><ul><li><strong>文档链接</strong>： <ul><li><a href="./cas-overlay-5.3.x-maven.html">Maven 版本</a></li><li><a href="./cas-overlay-5.3.x-gradle.html">Gradle 版本</a></li></ul></li></ul><h2 id="版本对比" tabindex="-1">版本对比 <a class="header-anchor" href="#版本对比" aria-label="Permalink to &quot;版本对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>5.3.x</th><th>6.6.x</th><th>7.3.x</th></tr></thead><tbody><tr><td><strong>JDK</strong></td><td>1.8</td><td>11</td><td>21</td></tr><tr><td><strong>Spring Boot</strong></td><td>2.x</td><td>2.x</td><td>3.x</td></tr><tr><td><strong>Servlet API</strong></td><td>javax.servlet</td><td>javax.servlet</td><td>jakarta.servlet</td></tr><tr><td><strong>Gradle</strong></td><td>7.5</td><td>7.5</td><td>9.1.0</td></tr><tr><td><strong>MySQL</strong></td><td>8.0.33</td><td>8.0.33</td><td>8.0.33</td></tr><tr><td><strong>Redis</strong></td><td>7.2.4</td><td>7.2.4</td><td>7.2.4</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><p>CAS-Overlay 企业级定制开发版</p><p>专为企业级身份认证场景深度二次开发，彻底重构原生 CAS 架构，开箱即用、零门槛适配企业各类账号体系，完美支撑微服务、分布式、容器化部署需求，解决原生 CAS 部署配置复杂、调试困难等核心痛点。</p><p>核心二次开发功能：</p><p>01：架构现代化升级 摒弃传统 WAR 包架构，全面转型 SpringBoot 标准 JAR 包架构，部署流程极简优化，原生适配微服务生态与 Docker / K8s 容器化部署，兼容企业现代化运维体系。</p><p>02：双源认证全覆盖 / JDBC + LDAP 集成 MyBatis 数据库访问框架，支持 JDBC 数据库账号认证 + LDAP 目录服务双认证模式，无缝对接企业现有账号存储方案，无需改造原有账号体系，满足内网、混合架构等全场景身份校验需求。</p><p>03：本地开发零障碍 / 自定义启动类 提供专属CasWebApplication主启动类，支持本地直接 Debug 启动、断点调试，告别原生 CAS 复杂启动配置，大幅提升开发调试效率。</p><p>04：灵活自定义认证逻辑 摒弃原生固定校验规则，支持完全自定义用户名 / 密码登录校验逻辑（JDBC模式），可按需再扩展验证码、多因子校验、账号状态校验等个性化验证规则。</p><p>05：双协议认证 / 任意自定义返回值 同时支持 OAuth2.0 + OIDC 双标准认证协议，兼容各类第三方应用对接需求；支持自定义认证返回值，可灵活输出用户详情、角色权限、部门信息等任意自定义业务数据。</p><p>06：分布式集群部署 / 高可用支撑 基于 Redis 实现 Ticket 集中存储，支持多节点分布式集群部署，无状态设计保障系统高可用性、横向扩展性，满足企业高并发访问场景。</p><p>07：安全加固 / 杜绝默认风险 强制关闭 CAS 原生默认账号密码登录，全权交由自定义认证类管控，从源头消除安全漏洞，符合企业级安全管控标准。</p><p>08：全量前端资源开放 / 可视化定制 完整提取前端静态资源、页面模板，无加密、无限制，支持开发者根据企业品牌自由定制登录页、首页、错误页等前端界面。</p><p>09：国际化多语言支持 内置中文、英文等多语言配置，满足企业国际化业务、跨区域使用需求。（示例）</p><p>10：容器化 / 自动化部署 内置标准化 DockerFile 与 Jenkins 部署脚本，一键完成容器打包、自动化部署，无缝接入企业 CI / CD 持续集成流程。</p><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li><strong>技术支持</strong>：北京必码科技工作室</li><li><strong>官方文档</strong>：<a href="https://bima.cc" target="_blank" rel="noreferrer">https://bima.cc</a></li><li><strong>官方店铺</strong>：<a href="https://bima.taobao.com" target="_blank" rel="noreferrer">https://bima.taobao.com</a></li><li><strong>联系邮箱</strong>：<a href="mailto:bima.cc@qq.com" target="_blank" rel="noreferrer">bima.cc@qq.com</a></li><li><strong>联系微信</strong>：e18929958</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ol><li><strong>选择版本</strong>：根据您的 JDK 版本和构建工具偏好选择合适的 CAS Overlay 版本</li><li><strong>查看文档</strong>：点击上方对应版本的链接查看详细文档</li><li><strong>环境准备</strong>：按照文档要求准备 JDK、MySQL、Redis 等环境</li><li><strong>数据库初始化</strong>：执行提供的数据库初始化脚本（<code>db_uc_20260113.sql</code>）</li><li><strong>配置修改</strong>：根据您的环境修改数据库连接、Redis 连接等配置</li><li><strong>构建运行</strong>：使用 Maven 或 Gradle 构建并运行项目</li><li><strong>访问服务</strong>：通过 <code>https://服务器IP:8443/cas/login</code> 访问 CAS 服务</li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><strong>安全提示</strong>：首次登录后请修改默认管理员密码</li><li><strong>证书警告</strong>：测试环境下访问会提示证书警告，可忽略或添加信任</li><li><strong>网络要求</strong>：构建过程需要访问 Maven 中央仓库，确保网络连接正常</li><li><strong>生产环境</strong>：在生产环境中使用前，请进行充分的测试和验证</li></ul>',39)])])}const b=e(n,[["render",d]]);export{S as __pageData,b as default};
